steps.content:
{
  "success": true,
  "data": "[
  {
    "id": "aeso_daily_average_pool_price",
    "name": "AESO Daily Average Pool Price",
    "description": "Average daily prices in AESO. AESO reports out prices for both peak (Hour Ending 8-23) and off-peak. This dataset also contains 30-day rolling average price, defined as the average of the current date and the prior 29 days. "
  },
  {
    "id": "aeso_fuel_mix",
    "name": "AESO Fuel Mix",
    "description": "Fuel mix data in AESO. This data is sampled every 1-2 minutes.  "
  },
  {
    "id": "aeso_interchange",
    "name": "AESO Interchange",
    "description": "This dataset contains the flows between AESO and British Columbia, Montana, and Saskatchewan. Positive values indicate exports and negative values indicate imports. Flows are sampled every 1-2 minutes. "
  },
  {
    "id": "aeso_load",
    "name": "AESO Load",
    "description": "Calculated total Alberta demand based on all telemetered Control Area Net Generation minus Net Actual Interchange (in MW)."
  },
  {
    "id": "aeso_load_forecast",
    "name": "AESO Load Forecast",
    "description": "Forecasted and calculated total Alberta demand based on all telemetered Control Area Net Generation minus Net Actual Interchange (in MW). Forecasts are released each day around 7AM Mountain Prevailing Time, forecasting the next 13 days. "
  },
  {
    "id": "aeso_outages_hourly",
    "name": "AESO Outages Hourly",
    "description": "This dataset contains hourly average MW values for AESO outages over the next 90 days, broken down by fuel type. Fuel types include simple cycle (SC), cogen, combined cycle (CC), gas-fired steam (GFS), hydro, wind, solar, energy storage, biomass and other, and units mothballed (MBO). "
  },
  {
    "id": "aeso_pool_price",
    "name": "AESO Pool Price",
    "description": "Time-weighted hourly averages of the one-minute system marginal prices across AESO. "
  },
  {
    "id": "aeso_pool_price_forecast",
    "name": "AESO Pool Price Forecast",
    "description": "Forecasted pool prices for AESO for the current and next two hours. "
  },
  {
    "id": "aeso_reserves",
    "name": "AESO Reserves",
    "description": "This dataset contains operating and required reserve values, in MWs, in AESO.  Values are included for Contingency Reserve, Fast Frequency Reserve (FFR), and Long Lead Time. AESO separates dispatched contingency reserves into two categories: generation and other. Other contingency reserves include load and interconnections. Data is sampled every 1-2 minutes. "
  },
  {
    "id": "aeso_solar_10_min",
    "name": "AESO Solar 10 Min",
    "description": "AESO's actual solar generation at 10 minute frequency. "
  },
  {
    "id": "aeso_solar_forecast_12_hour",
    "name": "AESO Solar Forecast 12 Hour",
    "description": "This dataset contains AESO\u2019s forecasted solar generation for the next 12 hours, calculated every 10 minutes. AESO calculates three generation forecasts: minimum, most likely, and maximum. Additionally, AESO calculates a percentage of generation compared to the current installed capacity for each forecast range. "
  },
  {
    "id": "aeso_solar_forecast_7_day",
    "name": "AESO Solar Forecast 7 Day",
    "description": "This dataset contains AESO\u2019s forecasted solar generation for the next 7 days, calculated every hour. AESO calculates three generation forecasts: minimum, most likely, and maximum. Additionally, AESO calculates a percentage of generation compared to the current installed capacity for each forecast range. "
  },
  {
    "id": "aeso_solar_hourly",
    "name": "AESO Solar Hourly",
    "description": "AESO's actual solar generation at an hourly frequency. "
  },
  {
    "id": "aeso_supply_and_demand",
    "name": "AESO Supply And Demand",
    "description": "Supply and demand information in AESO, sampled every 1-2 minutes. "
  },
  {
    "id": "aeso_system_marginal_price",
    "name": "AESO System Marginal Price",
    "description": "This dataset contains the system marginal price (SMP) across AESO. The SMP is calculated each minute based off of the cost of the next MW dispatched to meet an additional MW of load. "
  },
  {
    "id": "aeso_transmission_outages",
    "name": "AESO Transmission Outages",
    "description": "This dataset contains information on transmission outages across IESO. Contained in this data are transmission owners, scheduled activity, and estimated length of outages."
  },
  {
    "id": "aeso_unit_status",
    "name": "AESO Unit Status",
    "description": "Unit-level status reports in AESO. AESO reports out the maximum capacity (MC), Total Net Generation (TNG), Gross Generation minus Asset service, and Dispatched (and Accepted) Contingency Reserve (DCR). This data is sampled every 1-2 minutes.   "
  },
  {
    "id": "aeso_wind_10_min",
    "name": "AESO Wind 10 Min",
    "description": "AESO's actual wind generation at 10 minute frequency. "
  },
  {
    "id": "aeso_wind_forecast_12_hour",
    "name": "AESO Wind Forecast 12 Hour",
    "description": "This dataset contains AESO\u2019s forecasted wind generation for the next 12 hours, calculated every 10 minutes. AESO calculates three generation forecasts: minimum, most likely, and maximum. Additionally, AESO calculates a percentage of generation compared to the current installed capacity for each forecast range. "
  },
  {
    "id": "aeso_wind_forecast_7_day",
    "name": "AESO Wind Forecast 7 Day",
    "description": "This dataset contains AESO\u2019s forecasted wind generation for the next 7 days, calculated every hour. AESO calculates three generation forecasts: minimum, most likely, and maximum. Additionally, AESO calculates a percentage of generation compared to installed capacity for each forecast range. "
  },
  {
    "id": "aeso_wind_hourly",
    "name": "AESO Wind Hourly",
    "description": "AESO's actual wind generation at an hourly frequency. "
  },
  {
    "id": "all_records",
    "name": "All Records",
    "description": "Top daily records for various metrics across all ISOs"
  },
  {
    "id": "all_records_timeseries",
    "name": "All Records Timeseries",
    "description": "Timeline of new records for various metrics in all ISOs"
  },
  {
    "id": "caiso_as_prices",
    "name": "CAISO AS Prices",
    "description": "Ancillary Services Prices as reported by CAISO. Not all regions report prices for each hour, day, or even year. \n\nAS_CAISO, AS_CAISO_EXP, AS_NP26, AS_NP26_EXP, AS_SP26, and AS_SP26_EXP have consistent data throughout the series. AS_SP15 and AS_NP15 are nested within other zones and record prices very infrequently.\n\n**AS Mapping**\n\nThe *_EXP show only the intertie resources.\n \n-    AS_SP26_P: Resources in AS_SP26\n-    AS_NP26_P: Resources in AS_NP26\n-    AS_SP15_P: Resources in AS_SP15\n-    AS_NP15_P: Resources in AS_NP15\n-    AS_SP26_EXP_P: Resources in AS_SP26_EXP which are not in AS_SP26\n-    AS_NP26_EXP_P: Resources in AS_NP26_EXP which are not in AS_NP26\n-    AS_SP15_EXP_P: Resources in AS_SP15_EXP which are not in AS_SP15\n-    AS_NP15_EXP_P: Resources in AS_NP15_EXP which are not in AS_NP15\n-    AS_CAISO_NP26_P: Resources in AS_CAISO which are not in AS_SP26\n-    AS_CAISO_SP26_P: Resources in AS_CAISO which are not in AS_NP26\n-    AS_CAISO_NP15_P: Resources in AS_CAISO which are not in AS_SP15\n-    AS_CAISO_SP15_P: Resources in AS_CAISO which are not in AS_NP15"
  },
  {
    "id": "caiso_as_procurement_dam",
    "name": "CAISO AS Procurement DAM",
    "description": "Ancillary services procurement data from CAISO.\nIncludes total MW procured and costs.  Corresponds\nto CAISO AS_RESULTS dataset on OASIS. See caiso_as_prices dataset\nfor per MW prices that result from market run."
  },
  {
    "id": "caiso_branch_shadow_prices_dam_hourly",
    "name": "CAISO Branch Shadow Prices DAM Hourly",
    "description": "Hourly day-ahead constraint pricing in CAISO at each Nomogram and Branch. \n\nCAISO uses Nomograms to: \u201cdefine a constraint relationship between two power system MW variables.\u201d  See section 3.1.7 of the Market+Operations Business Practice Manual for more information on CAISO\u2019s use of Nomograms. "
  },
  {
    "id": "caiso_branch_shadow_prices_hasp_hourly",
    "name": "CAISO Branch Shadow Prices HASP Hourly",
    "description": "Constraint pricing in CAISO at each Nomogram and Branch from the hour-ahead scheduling process. \n\nCAISO uses Nomograms to: \u201cdefine a constraint relationship between two power system MW variables.\u201d  See section 3.1.7 of the Market+Operations Business Practice Manual for more information on CAISO\u2019s use of Nomograms. "
  },
  {
    "id": "caiso_branch_shadow_prices_rtm_5_min",
    "name": "CAISO Branch Shadow Prices RTM 5 Min",
    "description": "Five-minute real-time constraint pricing in CAISO at each Nomogram and Branch. \n\nCAISO uses Nomograms to: \u201cdefine a constraint relationship between two power system MW variables.\u201d  See section 3.1.7 of the Market+Operations Business Practice Manual for more information on CAISO\u2019s use of Nomograms. "
  },
  {
    "id": "caiso_branch_shadow_prices_rtpd_15_min",
    "name": "CAISO Branch Shadow Prices RTPD 15 Min",
    "description": "Fifteen-minute real-time pre-dispatch constraint pricing in CAISO at each Nomogram and Branch. \n\nCAISO uses Nomograms to: \u201cdefine a constraint relationship between two power system MW variables.\u201d  See section 3.1.7 of the Market+Operations Business Practice Manual for more information on CAISO\u2019s use of Nomograms. "
  },
  {
    "id": "caiso_curtailed_non_operational_generator_report",
    "name": "CAISO Curtailed Non Operational Generator Report",
    "description": "Prior Day Curtailed Non-Operational Generator Report as reported by CAISO.\n\nGlossary: https://www.caiso.com/glossary"
  },
  {
    "id": "caiso_curtailment",
    "name": "CAISO Curtailment",
    "description": "Daily Curtailment data as reported by CAISO.\n\nNote: CAISO did not publish curtailment reports for 2024-07-26 and 2024-07-27."
  },
  {
    "id": "caiso_curtailment_aggregated_hourly",
    "name": "CAISO Curtailment Aggregated Hourly",
    "description": "CAISO curtailment aggregated by wind and solar on an hourly basis. For more granular data, on curtailment type and reason, see the caiso_curtailment dataset."
  },
  {
    "id": "caiso_fuel_mix",
    "name": "CAISO Fuel Mix",
    "description": "Fuel Mix in 5 minute intervals as reported by CAISO.\n\n\u26a0\ufe0f For this data, CAISO reports only 24 hours even on DST days when 25 are reported elsewhere."
  },
  {
    "id": "caiso_fuel_prices",
    "name": "CAISO Fuel Prices",
    "description": "Hourly natural fuel prices in $/MMBtu by fuel region."
  },
  {
    "id": "caiso_fuel_prices_and_descriptions",
    "name": "CAISO Fuel Prices and Descriptions",
    "description": "Fuel prices as reported by CAISO with detailed names and descriptions where available.\n\nFor the raw fuel price data, see [CAISO Fuel Prices](https://www.gridstatus.io/datasets/caiso_fuel_prices)."
  },
  {
    "id": "caiso_fuel_regions",
    "name": "CAISO Fuel Regions",
    "description": "List of ISO fuel regions and electric regions with IDs, names, and descriptions."
  },
  {
    "id": "caiso_intertie_constraint_shadow_prices_real_time_5_min",
    "name": "CAISO Intertie Constraint Shadow Prices Real Time 5 Min",
    "description": "Five-minute constraint pricing in CAISO at both transmission interfaces and intertie constraints.\n"
  },
  {
    "id": "caiso_lmp_dart_15_min",
    "name": "CAISO LMP DART 15 Min",
    "description": "DART spread in CAISO between day-ahead hourly LMPs and real-time 15-minute LMPs. Hourly day-ahead values are brought to a 15-minute interval across the hour for the purposes of this dataset."
  },
  {
    "id": "caiso_lmp_dart_5_min",
    "name": "CAISO LMP DART 5 Min",
    "description": "DART spread in CAISO between day-ahead hourly LMPs and real-time 5-minute LMPs. Hourly day-ahead values are brought to a five-minute interval across the hour for the purposes of this dataset."
  },
  {
    "id": "caiso_lmp_day_ahead_hourly",
    "name": "CAISO LMP Day Ahead Hourly",
    "description": "Day-ahead hourly locational marginal prices (LMPs) for locations administered by CAISO internally as well as certain external points for which CAISO calculates day-ahead prices. Inclues AP Nodes, Trading Hubs, and Nodes."
  },
  {
    "id": "caiso_lmp_hasp_15_min",
    "name": "CAISO LMP HASP 15 Min",
    "description": "15-minute Locational Marginal Prices in $/MWh, for the HASP hour. Posts the LMP, plus the Congestion, Loss and Energy Components that make up the LMP. Posts the HASP Binding LMP for PNodes and APNodes relevant to Hourly Pre-Dispatched Resources. Posts the HASP Advisory LMP for PNodes and APNodes relevant to the Non-Hourly Pre-Dispatch Resources."
  },
  {
    "id": "caiso_lmp_real_time_15_min",
    "name": "CAISO LMP Real Time 15 Min",
    "description": "Real-time 15-minute locational marginal prices (LMPs) for locations administered by CAISO internally as well as through the WEIM. Inclues AP Nodes, Trading Hubs, and Nodes."
  },
  {
    "id": "caiso_lmp_real_time_5_min",
    "name": "CAISO LMP Real Time 5 Min",
    "description": "Real-time 5-minute locational marginal prices (LMPs) for locations administered by CAISO internally as well as through the WEIM. Inclues AP Nodes, Trading Hubs, and Nodes."
  },
  {
    "id": "caiso_lmp_scheduling_point_tie_dart_15_min",
    "name": "CAISO LMP Scheduling Point Tie DART 15 Min",
    "description": "DART spread in CAISO between day-ahead hourly LMPs and real-time 15-minute LMPs for scheduling point tie locations. Hourly day-ahead values are brought to a 15-minute interval across the hour for the purposes of this dataset."
  },
  {
    "id": "caiso_lmp_scheduling_point_tie_dart_5_min",
    "name": "CAISO LMP Scheduling Point Tie DART 5 Min",
    "description": "DART spread in CAISO between day-ahead hourly LMPs and real-time 5-minute LMPs for scheduling point tie locations. Hourly day-ahead values are brought to a 5-minute interval across the hour for the purposes of this dataset."
  },
  {
    "id": "caiso_lmp_scheduling_point_tie_day_ahead_hourly",
    "name": "CAISO LMP Scheduling Point Tie Day Ahead Hourly",
    "description": "Hourly LMPs for Scheduling Point (SP) - Intertie (Tie) combinations. Interchange schedules are settled at the relevant SP-Tie combination. Both the SP and the Tie are declared by a scheduling coordinator when submitting a bid, while for registered system resources, the SP is their PNode/APNode, and the Tie is the registered primary intertie. "
  },
  {
    "id": "caiso_lmp_scheduling_point_tie_real_time_15_min",
    "name": "CAISO LMP Scheduling Point Tie Real Time 15 Min",
    "description": "Fifteen-minute LMPs for Scheduling Point (SP) - Intertie (Tie) combinations. Interchange schedules are settled at the relevant SP-Tie combination. Both the SP and the Tie are declared by a scheduling coordinator when submitting a bid, while for registered system resources, the SP is their PNode/APNode, and the Tie is the registered primary intertie. "
  },
  {
    "id": "caiso_lmp_scheduling_point_tie_real_time_5_min",
    "name": "CAISO LMP Scheduling Point Tie Real Time 5 Min",
    "description": "Five-minute LMPs for Scheduling Point (SP) - Intertie (Tie) combinations. Interchange schedules are settled at the relevant SP-Tie combination. Both the SP and the Tie are declared by a scheduling coordinator when submitting a bid, while for registered system resources, the SP is their PNode/APNode, and the Tie is the registered primary intertie. \n\nThe data is known to contain gaps originating in the CAISO Source."
  },
  {
    "id": "caiso_load",
    "name": "CAISO Load",
    "description": "Load in 5 minute intervals as reported by CAISO. Does not include load from storage charging."
  },
  {
    "id": "caiso_load_forecast",
    "name": "CAISO Load Forecast",
    "description": "Load Forecast resampled to 5 minute intervals"
  },
  {
    "id": "caiso_load_forecast_15_min",
    "name": "CAISO Load Forecast 15 Min",
    "description": "Load forecast in CAISO in 15-minute intervals."
  },
  {
    "id": "caiso_load_forecast_2_day",
    "name": "CAISO Load Forecast 2 Day",
    "description": "Hourly load forecast data for each hour of an operating day in CAISO, published two days prior to the operating day."
  },
  {
    "id": "caiso_load_forecast_5_min",
    "name": "CAISO Load Forecast 5 Min",
    "description": "5-minute load forecast data from the Very Short Term Load Forecast (VSTLF) used by CAISO in Real-Time Dispatch (RTD)."
  },
  {
    "id": "caiso_load_forecast_7_day",
    "name": "CAISO Load Forecast 7 Day",
    "description": "Hourly load forecast data for each hour of an operating day in CAISO, published seven days prior to the operating day."
  },
  {
    "id": "caiso_load_forecast_dam",
    "name": "CAISO Load Forecast DAM",
    "description": "\u26a0\ufe0f This dataset is deprecated in favor of [CAISO Load Forecast Day Ahead](https://www.gridstatus.io/datasets/caiso_load_forecast_day_ahead). It is the same dataset from the same source, but includes all \"TAC Area Names\" rather than only the system area like this dataset. It also includes a slightly more accurate publish time.\n\n---\nLoad Forecast in 1 hour intervals as reported by CAISO.\n\n"
  },
  {
    "id": "caiso_load_forecast_day_ahead",
    "name": "CAISO Load Forecast Day Ahead",
    "description": "Hourly load forecast data for each hour of the following day, which is the operating day. This load forecast is posted prior to CAISO running the day-ahead market for the operating day."
  },
  {
    "id": "caiso_load_hourly",
    "name": "CAISO Load Hourly",
    "description": "Actual hourly load reported by CAISO. Unlike [`caiso_load`](/datasets/caiso_load), the reported load includes load from charging storage."
  },
  {
    "id": "caiso_net_interchange_real_time",
    "name": "CAISO Net Interchange Real Time",
    "description": "Five-minute, real-time interchange in the West via CAISO data presented as a summarized view of flows between balacing authorities to enable easier BA-level analysis.\n\nThis view sums the MW values for each 5 minute interval for each unique pairing of from and to. This view does not contain individual ties. For tie-level data, refer to [caiso_tie_flows_real_time_5_min](https://www.gridstatus.io/datasets/caiso_tie_flows_real_time_5_min)."
  },
  {
    "id": "caiso_outages_aggregated_hourly",
    "name": "CAISO Outages Aggregated Hourly",
    "description": "CAISO Outages Aggregated by forced and planned on an hourly basis. For generator level data including the reason, see the caiso_curtailed_non_operational_generator dataset."
  },
  {
    "id": "caiso_records",
    "name": "CAISO Records",
    "description": "Top 10 daily records for various metrics in CAISO"
  },
  {
    "id": "caiso_records_timeseries",
    "name": "CAISO New Records Timeline",
    "description": "Timeline of new records for CAISO"
  },
  {
    "id": "caiso_renewables_forecast_dam",
    "name": "CAISO Renewables Forecast DAM",
    "description": "Day-ahead solar and wind forecasts by trading hub as reported by CAISO.\n\nIncludes data for solar and wind in CAISO, ZP26, SP15, and NP15."
  },
  {
    "id": "caiso_renewables_forecast_hasp",
    "name": "CAISO Renewables Forecast HASP",
    "description": "The Hour-Ahead Scheduling Process (HASP) renewables forecast published by CAISO. This is an hourly forecast published roughly 90 minutes before the forecasted interval.\n\nIncludes data for solar and wind in ZP26, SP15, and NP15."
  },
  {
    "id": "caiso_renewables_forecast_rtd",
    "name": "CAISO Renewables Forecast RTD",
    "description": "The five-minute Real-Time Dispatch (RTD) renewables forecast published by CAISO. Forecast data is published roughly 2.5 minutes before the forecasted interval.\n\nIncludes data for solar and wind in ZP26, SP15, and NP15."
  },
  {
    "id": "caiso_renewables_forecast_rtpd",
    "name": "CAISO Renewables Forecast RTPD",
    "description": "The FMM RTPD renewables forecast published by the market operator. Forecast data is published roughly 22.5 minutes before the forecasted interval."
  },
  {
    "id": "caiso_renewables_hourly",
    "name": "CAISO Renewables Hourly",
    "description": "Actual hourly generation from wind and solar in CAISO. \n\nIncludes data for all of CAISO as well as ZP26, SP15, and NP15."
  },
  {
    "id": "caiso_solar_and_wind_forecast_dam",
    "name": "CAISO Solar And Wind Forecast DAM",
    "description": "Day-ahead solar and wind forecasts by trading hub as reported by CAISO."
  },
  {
    "id": "caiso_standardized_5_min",
    "name": "CAISO 5 minute standardized data",
    "description": "This table is a curated set of five-minute data for CAISO. All standardized datasets are intended to speed up analysis and feature engineering work by providing commonly used data series in one denormalized table. \n\nThe standardized datasets are a conveience for API users who only want to query one dataset for each ISO. If you plan on loading in every dataset or want to work with more multiple series alone and together it is recommended to pull the individual datasets to have full visibility into each one.\n\n\u26a0\ufe0f Not all data series are present for the entire length of the dataset. This can occur due to a lack of historical data or the publication of new core datasets by an ISO."
  },
  {
    "id": "caiso_standardized_hourly",
    "name": "CAISO hourly standardized data",
    "description": "This table is a curated set of hourly data for CAISO. All standardized datasets are intended to speed up analysis and feature engineering work by providing commonly used data series in one denormalized table. Data in this feed is resampled to an hourly frequency from five minutes.\n\nThe standardized datasets are a conveience for API users who only want to query one dataset for each ISO. If you plan on loading in every dataset or want to work with more multiple series alone and together it is recommended to pull the individual datasets to have full visibility into each one.\n\n\u26a0\ufe0f Not all data series are present for the entire length of the dataset. This can occur due to a lack of historical data or the publication of new core datasets by an ISO."
  },
  {
    "id": "caiso_storage",
    "name": "CAISO Storage",
    "description": "Data on storage and hybrid resources as reported by CAISO."
  },
  {
    "id": "caiso_system_load_and_resource_schedules_day_ahead",
    "name": "CAISO System Load And Resource Schedules Day Ahead",
    "description": "Day-ahead hourly CAISO system schedule. Includes generation, imports, and exports per TAC Area to balance the CAISO system."
  },
  {
    "id": "caiso_system_load_and_resource_schedules_hasp",
    "name": "CAISO System Load and Resource Schedules HASP",
    "description": "HASP hourly CAISO system schedule. Includes generation, imports, and exports per TAC Area to balance the CAISO system."
  },
  {
    "id": "caiso_system_load_and_resource_schedules_real_time_5_min",
    "name": "CAISO System Load And Resource Schedules Real Time 5 Min",
    "description": "Real-time 5-minute CAISO system schedule. Includes generation, imports, and exports per TAC Area to balance the CAISO system."
  },
  {
    "id": "caiso_system_load_and_resource_schedules_ruc",
    "name": "CAISO System Load and Resource Schedules RUC",
    "description": "RUC hourly CAISO system schedule. Includes generation, imports, and exports per TAC Area to balance the CAISO system."
  },
  {
    "id": "caiso_tie_flows_real_time_15_min",
    "name": "CAISO Tie Flows Real Time 15 Min",
    "description": "Fifteen-minute real-time CAISO tie data. Includes all transfers within the EIM."
  },
  {
    "id": "caiso_tie_flows_real_time_5_min",
    "name": "CAISO Tie Flows Real Time 5 Min",
    "description": "Five-minute real-time CAISO tie data. Includes all transfers within the EIM."
  },
  {
    "id": "eia_ba_interchange_hourly",
    "name": "EIA BA Interchange Hourly",
    "description": "Balancing Authority (BA) Interchange Data in hourly intervals as reported in the EIA-930 dataset. This dataset contains both \"to\" and \"from\" for each BA.\n\n\u26a0\ufe0f For the most accurate and up to date ISO/RTO interchange data, we recommend using their respective datasets instead.\n\n \ud83d\udcdd This dataset was utilized in *[SPP Expansion Provides a Blueprint for the Future of the Grid](https://blog.gridstatus.io/spp-expansion-west/)*\n\n\u2139\ufe0f We recheck historical data for 30 days after publication in case of updates. Updates are applied only when the new values are non-null."
  },
  {
    "id": "eia_co2_emissions",
    "name": "EIA CO2 Emissions",
    "description": "Hourly emissions data for each EIA area. Includes Balancing Authorities and Regions. Emissions from generation, imports, and exports reported in metric tons. Emissions intensity reported in lbs/KWh"
  },
  {
    "id": "eia_fuel_mix_hourly",
    "name": "EIA Fuel Mix Hourly",
    "description": "Hourly fuel mix for all regions and balancing authorities in the United States as reported by the EIA-930 dataset.\n\n\u2139\ufe0f EIA data can be delayed or revised. To avoid missing updates, we:\n* Check for new data and revisions throughout the day for the previous 24 hours.\n* At 04:00 UTC, recheck the past 30 days for any changes.\nIn both cases, updates are only applied when the new values are non-null.\n\n\u26a0\ufe0f For the most accurate and up to date ISO/RTO fuel data, we recommend using their respective datasets instead.\n\n\ud83d\udcdd This dataset was utilized in *[SPP Expansion Provides a Blueprint for the Future of the Grid](https://blog.gridstatus.io/spp-expansion-west/)*\n"
  },
  {
    "id": "eia_henry_hub_natural_gas_spot_prices_daily",
    "name": "EIA Henry Hub Natural Gas Spot Prices Daily",
